metadata.mermaid:
classDiagram
  class Persona {
    +String nombre
    +int edad
  }
  class Cliente {
    +String rfc
    +comprar()
  }
  class Pedido {
    +int folio
    +calcularTotal() float
  }
  class LineaPedido {
    +int cantidad
    +float precio
  }
  Persona <|-- Cliente
  Cliente "1" --> "*" Pedido : realiza
  Pedido "1" *-- "*" LineaPedido : contiene
